UPDATE ai_prompt_templates
SET body = 'Виртуальная примерка одежды для интернет-магазина (как на Wildberries/Ozon). На фото image1 — покупатель: ЕДИНСТВЕННЫЙ источник лица, волос, тона кожи и фигуры. На фото image2 — товар с карточки маркетплейса (часто с моделью в одежде). С image2 возьми ТОЛЬКО одежду — цвет, крой, ткань и детали. Лицо, голову и тело модели на image2 НЕ использовать. Одень человека с image1 в вещь с image2. Лицо, причёска, черты и пропорции тела — строго с image1. Не уменьшай грудь, бёдра и талию под размер на бирке. Человек полностью одет только в товар с image2; прежняя одежда и бельё не должны быть видны. Фотореализм, нейтральный студийный фон, спокойная стойка, вертикаль 3:4. Семейный PG-контент каталога магазина — домашняя/повседневная одежда, не эротика и не откровенный контент.',
    updated_at = CURRENT_TIMESTAMP
WHERE template_key = 'vton.base_ru';
